// Normalizar respuesta de Thingiverse al formato RenderHub
const hits = $('GET Thingiverse Search').first().json.hits || [];
const query = $('Trigger Sub-Workflow').first().json.query || '';

const normalized = hits.map(item => ({
  platform: 'Thingiverse',
  id: String(item.id),
  name: item.name || '',
  description: (item.description || '').replace(/<[^>]*>/g, '').slice(0, 300),
  thumbnail_url: item.thumbnail || item.preview_image || '',
  page_url: item.public_url || `https://www.thingiverse.com/thing:${item.id}`,
  download_url: `https://www.thingiverse.com/thing:${item.id}/zip`,
  stl_direct: true,
  files_endpoint: `https://api.thingiverse.com/things/${item.id}/files`,
  creator: item.creator?.name || '',
  likes: item.like_count || 0,
  downloads: item.download_count || 0,
  tags: (item.tags || []).map(t => t.name || t).slice(0, 8)
}));

return {
  platform: 'Thingiverse',
  query,
  count: normalized.length,
  results: normalized
};

